import { CommonModule } from '@angular/common';
import { Component, input, viewChild } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { Id, IVirtualListItemConfigMap, MethodForSelecting, MethodsForSelecting, NgVirtualListComponent, ScrollBarTheme, SnappingMethod, SnappingMethods, TextDirection, TextDirections } from "ng-virtual-list";
import { HORIZONTAL_GROUP_ITEMS_ITEM_CONFIG_MAP, HORIZONTAL_GROUP_ITEMS } from '../app/utils';

@Component({
    selector: 'horizontal-grouped-virtual-list',
    standalone: true,
    imports: [CommonModule, FormsModule, NgVirtualListComponent],
    template: `
    <div class="wrapper">
        <div class="vl-section block cap">
            <h1 class="center">ng-virtual-list</h1>
            <p class="l">Maximum performance for extremely large lists</p>
            <p class="l">Works correctly in all browsers and platforms</p>
            <p class="l">Animation of elements is supported.</p>
            <p class="l m" style="margin-bottom: 0;">&#64;author: Evgenii Grebennikov</p>
            <p class="l m">djonnyx&#64;gmail.com</p>
            <img class="logo" src="data:image/png;base64," />
            <div class="version"><span>v 14.X - v 21.X</span></div>
        </div>

        <div class="vl-section">
            <div class="vl-section__container">
            <h2>Horizontal grouped virtual list</h2>
                <div class="scroll-to__controls">
                    <input type="number" class="scroll-to__input" [(ngModel)]="itemId" [required]="true" [min]="minId"
                    [max]="maxId">
                    <button class="scroll-to__button" (click)="onButtonScrollToIdClickHandler($event)">Scroll</button>
                </div>
                <ng-virtual-list #virtualList class="list" [items]="items" [itemRenderer]="itemRenderer" direction="horizontal" [bufferSize]="bufferSize()" [enabledBufferOptimization]="enabledBufferOptimization()" [screenReaderMessage]="screenReaderMessage()"
                [maxBufferSize]="maxBufferSize()" [dynamicSize]="dynamicSize()" [itemSize]="itemSize()" [methodForSelecting]="methodForSelecting()" [itemConfigMap]="itemConfigMap()" [snap]="snap()" [selectByClick]="selectByClick()" [collapseByClick]="collapseByClick()"
                [[snappingMethod]="snappingMethod()" [langTextDir]="langTextDir()" [loading]="loading()" [scrollbarTheme]="scrollbarTheme()"
                [clickDistance]="clickDistance()" [waitForPreparation]="waitForPreparation()" [scrollStartOffset]="scrollStartOffset()"
                [scrollEndOffset]="scrollEndOffset()" [snapScrollToBottom]="snapScrollToBottom()" [snapToEndTransitionInstantOffset]="snapToEndTransitionInstantOffset()" [scrollbarMinSize]="scrollbarMinSize()"
                [selectedIds]="selectedIds()" [collapsedIds]="collapsedIds()" (onScrollReachStart)="onScrollReachStartHandler()" (onScrollReachEnd)="onScrollReachEndHandler()"></ng-virtual-list>
                <ng-template #itemRenderer let-data="data" let-config="config">
                    @if (data) {
                    @switch (data.type) {
                        @case ("group-header") {
                        <div [ngClass]="{'list__h-group-container': true, 'even': config.even, 'selected': config.selected}">
                            <span>{{data.name}}</span>
                        </div>
                        }
                        @default {
                        <div [ngClass]="{'list__h-container': true, 'even': config.even, 'selected': config.selected}">
                            <span>{{data.name}}</span>
                        </div>
                        }
                    }
                    }
                </ng-template>
            </div>
        </div>
    </div>
  `,
    styleUrls: ['./list-styles.scss'],
})
export class HorizontalGroupedVirtualListComponent {
    readonly items = [...HORIZONTAL_GROUP_ITEMS];

    bufferSize = input<number>(5);

    maxBufferSize = input<number>(20);

    enabledBufferOptimization = input<boolean>(false);

    itemSize = input<number>(54);

    dynamicSize = input<boolean>(false);

    snap = input<boolean>(false);

    collapseByClick = input<boolean>(false);

    selectByClick = input<boolean>(true);

    selectedIds = input<Array<Id> | Id | undefined>();

    collapsedIds = input<Array<Id>>([]);

    methodForSelecting = input<MethodForSelecting>(MethodsForSelecting.NONE);

    itemConfigMap = input<IVirtualListItemConfigMap>(HORIZONTAL_GROUP_ITEMS_ITEM_CONFIG_MAP);

    screenReaderMessage = input<string>("Showing items $1 to $2");

    snappingMethod = input<SnappingMethod>(SnappingMethods.NORMAL);

    langTextDir = input<TextDirection>(TextDirections.LTR);

    loading = input<boolean>(false);

    scrollbarTheme = input<ScrollBarTheme>({
        fill: ["rgba(51, 0, 97, 1)", "rgba(73, 0, 97, 1)"],
        strokeGradientColor: ["rgba(133, 142, 255, 0)", "rgb(0, 133, 160)"],
        strokeAnimationDuration: 1000,
        thickness: 6,
        roundCorner: [3, 3, 3, 3],
        rippleColor: 'rgba(255,255,255,0.5)',
    });

    clickDistance = input<number>(40);

    waitForPreparation = input<boolean>(true);

    scrollStartOffset = input<number>(0);

    scrollEndOffset = input<number>(0);

    snapScrollToBottom = input<boolean>(false);

    snapToEndTransitionInstantOffset = input<number>(0);

    scrollbarMinSize = input<number>(80);

    protected _listContainerRef = viewChild('virtualList', { read: NgVirtualListComponent });

    private _minId: Id = this.items.length > 0 ? this.items[0].id : 0;
    get minId() { return this._minId; };

    private _maxId: Id = this.items.length > 0 ? this.items[this.items.length - 1].id : 0;
    get maxId() { return this._maxId; };

    itemId: Id = this._minId;

    onButtonScrollToIdClickHandler = (e: Event) => {
        const list = this._listContainerRef(), id = this.itemId;
        if (list && id !== undefined) {
            list.scrollTo(id, () => {
                list.focus(id);
                console.info(`scrollTo finished. id: ${id}`);
            }, {
                behavior: 'smooth',
            });
        }
    }

    onScrollReachStartHandler() {
        console.info(`onScrollReachStart`);
    }

    onScrollReachEndHandler() {
        console.info(`onScrollReachEnd`);
    }
}

